def move_vertical_collection(socket_conn, points_motion_cart, A, V):
    
    ur_script = "def my_program():\n"

    for item in points_motion_cart:
        pose_line = ','.join([str(x) for x in item])
        ur_script += f"  movel(p[{pose_line}], a={A}, v={V}, t=0, r=0)\n"
        # ur_script += "  sleep(1.0)\n"
    ur_script += "end\n"
    ur_script += "my_program()\n"
    
    socket_conn.sendall(ur_script.encode('ascii'))

"""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""

                                      TILTED TCP EXPERIMENT FUNCTIONS

"""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""""


def make_radial_tilt_pose_with_angle(base_pose, x_offset, y_offset, tilt_deg):
    pos = np.array(base_pose[:3])
    base_rot = R.from_rotvec(base_pose[3:6])

    r = np.sqrt(x_offset**2 + y_offset**2)

    if r < 1e-6:
        return base_pose.copy()

    radial_dir = np.array([x_offset, y_offset, 0.0])
    radial_dir = radial_dir / np.linalg.norm(radial_dir)

    tilt_axis_base = np.array([
        radial_dir[1],
        -radial_dir[0],
        0.0
    ])

    tilt_rad = np.deg2rad(tilt_deg)

    tilt_rot = R.from_rotvec(tilt_axis_base * tilt_rad)

    new_rot = tilt_rot * base_rot
    rotvec = new_rot.as_rotvec()

    return [
        pos[0], pos[1], pos[2],
        rotvec[0], rotvec[1], rotvec[2]
    ]


def tcp_press_direction(pose):
    rot = R.from_rotvec(pose[3:6])
    direction = rot.apply([0, 0, 1]) 
    return direction / np.linalg.norm(direction)

